  ('aboriginal-64311456-moex-00287', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '下列何者不屬於憲法上表現自由所涵蓋之範圍？', '["著作的自由", "參加集會的自由", "受大學教育之權利", "接近使用傳播媒體的權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00288', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '國家所為之差別待遇經常也涉及憲法上其他基本權利，下列何者尚未經司法院大法官解釋於平等權之 違憲審查中一併討論？', '["婚姻自由", "工作權", "隱私權", "應考試服公職權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00289', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依司法院大法官解釋，所得稅法有關扶養無謀生能力者之免稅額，係基於憲法保障之何種權利？', '["親權", "工作權", "生存權", "家庭團聚權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00290', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '關於特別公課，下列敘述何者錯誤？', '["特別公課相對於稅捐而言，所受法律保留原則之拘束較為寬鬆", "特別公課乃國家依特定公益目的，對特定國民所徵收之費用", "國家徵收特別公課之用途，必須符合法律規定始得為之", "被徵收特別公課者，依法得請求國家將公課用於特定用途"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00291', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依司法院大法官解釋，關於服兵役之義務與宗教信仰自由，下列敘述何者錯誤？', '["憲法保障人民有信仰與不信仰任何宗教之自由，國家不得對特定之宗教加以獎勵或禁制，或對人民 特定信仰給予優待或不利益", "立法者對於免役及禁役之規定，屬立法政策之考量，非為助長、促進或限制宗教而設，且無助長、 促進或限制宗教之效果", "內在信仰之自由，涉及思想、言論、信念及精神之層次，應受絕對之保障，故因宗教因素致不適服 役時，應免除其服兵役之義務", "人民如何履行兵役義務，憲法本身並無明文規定，有關人民服兵役之重要事項，應由立法者斟酌國 家安全、社會發展之需要，以法律定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00292', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依憲法增修條文規定，關於緊急命令之發布，下列敘述何者錯誤？', '["目的是為避免國家或人民遭遇緊急危難或應付財政經濟上重大變故", "總統得經行政院會議之決議，依緊急命令法發布之", "須於發布命令後10日內提交立法院追認", "如立法院不同意時，該緊急命令立即失效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00293', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '下列何者不屬於憲法本文所明定之行政院院長職權？', '["法令副署權", "代行總統職權", "提請總統任命閣員權", "呈請總統解散立法院之權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00294', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依司法院大法官解釋及相關規定，關於我國獨立機關，下列敘述何者錯誤？', '["獨立機關之首長得由委員互選產生", "依中央行政機關組織基準法規定，至多僅得設置三個相當二級機關之獨立機關", "獨立機關為依法律獨立行使職權，且不受其他機關指揮監督之合議制機關", "獨立機關本身對於機關委員應有完全之人事決定權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00295', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '依憲法及增修條文規定，關於立法權，下列敘述何者錯誤？', '["立法院為我國最高立法機關，採一院制，由立法委員組成之", "立法委員任期爲4年，連選得連任，應於每屆任滿前2個月內選出", "自由地區平地原住民及山地原住民應選出立法委員各3人", "自由地區各縣市至少應選出立法委員1人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL),
  ('aboriginal-64311456-moex-00296', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-6ed013db', 'sub-aboriginal-64311456-06', NULL, 'single_choice', '有關司法院大法官，下列敘述何者錯誤？', '["目前大法官法定總額為15人", "目前所有大法官之任期，均為8年，其任期並受保障", "大法官由總統提名，經立法院同意後任命之", "大法官具有審理立法院彈劾總統、副總統案之權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL)
